1	//! Route model for the interactive web UI.
2	//!
3	//! Every observed request path has the shape
4	//! `/thy/<theory-kind>/<index>/<handler>/<args…>` where:
5	//! * `<theory-kind>` is the analysis kind — only `trace` appears in the corpus
6	//!   (a `diff` kind is plausible but unobserved).
7	//! * `<index>` is either `#` (the "current" theory version) or a decimal number.
8	//! * `<handler>` selects the response family. Observed handlers and their
9	//!   response `kind`:
10	//!     - `main/…`                    -> JSON envelope (`{html,title}` / `{redirect}`)
11	//!     - `overview/…`                -> full-page HTML
12	//!     - `intdot/…`                  -> HTML mini-page
13	//!     - `interactive-graph-def/…`   -> DOT
14	//!     - `next/…`, `prev/…`          -> text (a navigation URL)
15	//!     - `autoprove/…`               -> JSON (`{redirect}`), or text on timeout
16	//!     - `source`, `message`         -> text (theory source)
17	//!
18	//! Under `main`, the sub-handlers are: `help`, `message`, `rules`, `tactic`,
19	//! `cases/{raw|refined}/{level}/{n}`, `lemma/{name}`, `add/{pos}`,
20	//! `edit/{name}`, `delete/{name}`, `method/{lemma}/{n}`, and
21	//! `proof/{lemma}/{path…}` (the proof path is a sequence of case-name segments,
22	//! the root being `_`).
23	//!
24	//! This module parses a path into a structured value; it is descriptive (the
25	//! route grammar as observed), not a dispatcher.
26	
27	/// Theory version selector.
28	#[derive(Debug, PartialEq, Eq, Clone)]
29	pub enum Index {
30	    /// `#` — the server's "current" theory version.
31	    Current,
32	    /// An explicit decimal version index.
33	    Num(u64),
34	}
35	
36	impl Index {
37	    fn parse(s: &str) -> Option<Index> {
38	        if s == "#" {
39	            Some(Index::Current)
40	        } else {
41	            s.parse::<u64>().ok().map(Index::Num)
42	        }
43	    }
44	}
45	
46	/// A `main/*` sub-handler.
47	#[derive(Debug, PartialEq, Eq, Clone)]
48	pub enum Main {
49	    Help,
50	    Message,
51	    Rules,
52	    Tactic,
53	    Cases { refined: bool, level: usize, n: usize },
54	    Lemma(String),
55	    Add(String),
56	    Edit(String),
57	    Delete(String),
58	    /// Apply proof method `n` at the node identified by `path` (a `/`-joined
59	    /// sequence of case-name segments, root `_`). The method number precedes the
60	    /// path in the URL: `method/{lemma}/{n}[/path…]` (observed live [L8] and in
61	    /// 67988 body links [Q032]).
62	    Method { lemma: String, n: usize, path: Vec<String> },
63	    Proof { lemma: String, path: Vec<String> },
64	    /// Any unrecognized `main/*` tail.
65	    Other(Vec<String>),
66	}
67	
68	/// The selected handler and its arguments.
69	#[derive(Debug, PartialEq, Eq, Clone)]
70	pub enum Handler {
71	    Source,
72	    Message,
73	    Main(Main),
74	    Overview(Vec<String>),
75	    Intdot(Vec<String>),
76	    InteractiveGraphDef(Vec<String>),
77	    Next(Vec<String>),
78	    Prev(Vec<String>),
79	    Autoprove(Vec<String>),
80	    /// Unrecognized handler with its raw tail.
81	    Other { name: String, tail: Vec<String> },
82	}
83	
84	/// A parsed route.
85	#[derive(Debug, PartialEq, Eq, Clone)]
86	pub struct Route {
87	    pub theory_kind: String,
88	    pub index: Index,
89	    pub handler: Handler,
90	}
91	
92	fn owned(v: &[&str]) -> Vec<String> {
93	    v.iter().map(|s| s.to_string()).collect()
94	}
95	
96	fn parse_main(tail: &[&str]) -> Main {
97	    match tail {
98	        ["help"] => Main::Help,
99	        ["message"] => Main::Message,
100	        ["rules"] => Main::Rules,
101	        ["tactic"] => Main::Tactic,
102	        ["cases", kind, level, n]
103	            if (*kind == "raw" || *kind == "refined")
104	                && level.parse::<usize>().is_ok()
105	                && n.parse::<usize>().is_ok() =>
106	        {
107	            Main::Cases {
108	                refined: *kind == "refined",
109	                level: level.parse().unwrap(),
110	                n: n.parse().unwrap(),
111	            }
112	        }
113	        ["lemma", name] => Main::Lemma((*name).to_string()),
114	        ["add", pos] => Main::Add((*pos).to_string()),
115	        ["edit", name] => Main::Edit((*name).to_string()),
116	        ["delete", name] => Main::Delete((*name).to_string()),
117	        ["method", lemma, n, rest @ ..] if n.parse::<usize>().is_ok() => Main::Method {
118	            lemma: (*lemma).to_string(),
119	            n: n.parse().unwrap(),
120	            path: owned(rest),
121	        },
122	        [proof, lemma, rest @ ..] if *proof == "proof" => Main::Proof {
123	            lemma: (*lemma).to_string(),
124	            path: owned(rest),
125	        },
126	        _ => Main::Other(owned(tail)),
127	    }
128	}
129	
130	impl Route {
131	    /// Parse a request path such as `/thy/trace/#/main/proof/exec/_/B_2`.
132	    /// Returns `None` if the path is not under `/thy/<kind>/<index>/…`.
133	    pub fn parse(path: &str) -> Option<Route> {
134	        let trimmed = path.strip_prefix('/').unwrap_or(path);
135	        let segs: Vec<&str> = trimmed.split('/').collect();
136	        // Need at least: thy / kind / index / handler
137	        if segs.len() < 4 || segs[0] != "thy" {
138	            return None;
139	        }
140	        let theory_kind = segs[1].to_string();
141	        let index = Index::parse(segs[2])?;
142	        let handler_name = segs[3];
143	        let tail = &segs[4..];
144	        let handler = match handler_name {
145	            "source" => Handler::Source,
146	            "message" => Handler::Message,
147	            "main" => Handler::Main(parse_main(tail)),
148	            "overview" => Handler::Overview(owned(tail)),
149	            "intdot" => Handler::Intdot(owned(tail)),
150	            "interactive-graph-def" => Handler::InteractiveGraphDef(owned(tail)),
151	            "next" => Handler::Next(owned(tail)),
152	            "prev" => Handler::Prev(owned(tail)),
153	            "autoprove" => Handler::Autoprove(owned(tail)),
154	            other => Handler::Other {
155	                name: other.to_string(),
156	                tail: owned(tail),
157	            },
158	        };
159	        Some(Route {
160	            theory_kind,
161	            index,
162	            handler,
163	        })
164	    }
165	}
