167	/// A parsed `autoprove/{strategy}/{bound}/{allSol}/proof/{lemma}[/path…]` request.
168	///
169	/// Observed variant matrix (corpus [Q030], keyboard help [Q031]): `strategy` is
170	/// `idfs` (solve/prove) or `characterize` (characterization, e.g. exists-trace);
171	/// `bound` is a depth bound (`0` = unbounded — the `a`/`A`/`s`/`S` shortcuts; `5`
172	/// = bounded — the `b`/`B` shortcuts); `all_solutions` is the `True`/`False` flag
173	/// (`False` = stop after the first solution, the lowercase shortcuts; `True` =
174	/// search for all solutions, the uppercase shortcuts).
175	#[derive(Debug, PartialEq, Eq, Clone)]
176	pub struct Autoprove {
177	    pub strategy: String,
178	    pub bound: u64,
179	    pub all_solutions: bool,
180	    pub lemma: String,
181	    pub path: Vec<String>,
182	}
183	
184	impl Autoprove {
185	    /// Parse the tail of an `autoprove/…` route (everything after `autoprove/`).
186	    pub fn parse(tail: &[String]) -> Option<Autoprove> {
187	        match tail {
188	            [strategy, bound, flag, proof, lemma, rest @ ..] if proof == "proof" => {
189	                Some(Autoprove {
190	                    strategy: strategy.clone(),
191	                    bound: bound.parse().ok()?,
192	                    all_solutions: parse_bool(flag)?,
193	                    lemma: lemma.clone(),
194	                    path: rest.to_vec(),
195	                })
196	            }
197	            _ => None,
198	        }
199	    }
200	}
