202	/// Navigation direction for `next`/`prev`.
203	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
204	pub enum NavDir {
205	    Next,
206	    Prev,
207	}
208	
209	/// A parsed `next|prev/{mode}/proof/{lemma}` request. `mode` (`normal` observed;
210	/// the server also accepts other tokens and passes them to the prover) selects the
211	/// prover's traversal function.
212	#[derive(Debug, PartialEq, Eq, Clone)]
213	pub struct Nav {
214	    pub dir: NavDir,
215	    pub mode: String,
216	    pub lemma: String,
217	}
218	
219	impl Nav {
220	    pub fn parse(dir: NavDir, tail: &[String]) -> Option<Nav> {
221	        match tail {
222	            [mode, proof, lemma] if proof == "proof" => Some(Nav {
223	                dir,
224	                mode: mode.clone(),
225	                lemma: lemma.clone(),
226	            }),
227	            _ => None,
228	        }
229	    }
230	}
