232	/// The full-page `overview/*` views. `help` and `proof/…` appear in the crawl;
233	/// `edit/{name}` and `add/{pos}` appear only as POST-redirect (303) targets
234	/// (live [L12]).
235	#[derive(Debug, PartialEq, Eq, Clone)]
236	pub enum OverviewView {
237	    Help,
238	    Proof { lemma: String, path: Vec<String> },
239	    Edit(String),
240	    Add(String),
241	    Other(Vec<String>),
242	}
243	
244	impl OverviewView {
245	    pub fn parse(tail: &[String]) -> OverviewView {
246	        match tail.iter().map(String::as_str).collect::<Vec<_>>().as_slice() {
247	            ["help"] => OverviewView::Help,
248	            ["proof", lemma, rest @ ..] => OverviewView::Proof {
249	                lemma: (*lemma).to_string(),
250	                path: rest.iter().map(|s| s.to_string()).collect(),
251	            },
252	            ["edit", name] => OverviewView::Edit((*name).to_string()),
253	            ["add", pos] => OverviewView::Add((*pos).to_string()),
254	            _ => OverviewView::Other(tail.to_vec()),
255	        }
256	    }
257	}
