259	/// The structural-edit verb of a POST `edit/{verb}/{name}` form target
260	/// (live [L12]/[L13]).
261	#[derive(Debug, PartialEq, Eq, Clone)]
262	pub enum EditVerb {
263	    Edit,
264	    Add,
265	    Delete,
266	}
267	
268	impl EditVerb {
269	    pub fn parse(s: &str) -> Option<EditVerb> {
270	        match s {
271	            "edit" => Some(EditVerb::Edit),
272	            "add" => Some(EditVerb::Add),
273	            "delete" => Some(EditVerb::Delete),
274	            _ => None,
275	        }
276	    }
277	}
278	
279	fn parse_bool(s: &str) -> Option<bool> {
280	    match s {
281	        "True" => Some(true),
282	        "False" => Some(false),
283	        _ => None,
284	    }
285	}
