293	        let r = Route::parse("/thy/trace/#/main/rules").unwrap();
294	        assert_eq!(r.theory_kind, "trace");
295	        assert_eq!(r.index, Index::Current);
296	        assert_eq!(r.handler, Handler::Main(Main::Rules));
