351	    #[test]
352	    fn parses_autoprove_variants() {
353	        let r = Route::parse("/thy/trace/1/autoprove/idfs/0/False/proof/types").unwrap();
354	        let tail = match r.handler {
355	            Handler::Autoprove(t) => t,
356	            _ => panic!("not autoprove"),
357	        };
358	        assert_eq!(
359	            Autoprove::parse(&tail).unwrap(),
360	            Autoprove {
361	                strategy: "idfs".into(),
362	                bound: 0,
363	                all_solutions: false,
364	                lemma: "types".into(),
365	                path: vec![],
366	            }
367	        );
368	        // characterize, bounded, all-solutions, with a path.
369	        let r = Route::parse("/thy/trace/1/autoprove/characterize/5/True/proof/L/_/B_2").unwrap();
370	        let tail = match r.handler {
371	            Handler::Autoprove(t) => t,
372	            _ => panic!(),
373	        };
374	        let ap = Autoprove::parse(&tail).unwrap();
375	        assert_eq!(ap.strategy, "characterize");
376	        assert_eq!(ap.bound, 5);
377	        assert!(ap.all_solutions);
378	        assert_eq!(ap.path, vec!["_".to_string(), "B_2".to_string()]);
379	    }
