381	    #[test]
382	    fn parses_nav_and_overview_views() {
383	        let r = Route::parse("/thy/trace/1/next/normal/proof/Client_auth").unwrap();
384	        if let Handler::Next(t) = r.handler {
385	            assert_eq!(
386	                Nav::parse(NavDir::Next, &t).unwrap(),
387	                Nav { dir: NavDir::Next, mode: "normal".into(), lemma: "Client_auth".into() }
388	            );
389	        } else {
390	            panic!();
391	        }
392	        assert_eq!(OverviewView::parse(&owned(&["help"])), OverviewView::Help);
393	        assert_eq!(
394	            OverviewView::parse(&owned(&["edit", "L"])),
395	            OverviewView::Edit("L".into())
396	        );
397	        assert_eq!(
398	            OverviewView::parse(&owned(&["proof", "L", "_", "B_2"])),
399	            OverviewView::Proof { lemma: "L".into(), path: vec!["_".into(), "B_2".into()] }
400	        );
401	    }
