37	/// `application/json; charset=utf-8`.
38	pub const CT_JSON: &str = "application/json; charset=utf-8";
39	/// `text/html; charset=utf-8`.
40	pub const CT_HTML: &str = "text/html; charset=utf-8";
41	/// `text/plain; charset=utf-8` (used for text bodies, `next`/`prev`, and DOT).
42	pub const CT_TEXT: &str = "text/plain; charset=utf-8";
43	
44	/// HTTP request method (only the two the UI uses are modelled).
45	#[derive(Debug, PartialEq, Eq, Clone, Copy)]
46	pub enum HttpMethod {
47	    Get,
48	    Post,
49	}
50	
51	/// An incoming request.
52	pub struct Request<'a> {
53	    pub method: HttpMethod,
54	    /// URL path, e.g. `/thy/trace/1/main/method/exec/1/_`.
55	    pub path: &'a str,
56	    /// Decoded POST form fields (e.g. `("lemma-text", "lemma foo: …")`).
57	    pub form: &'a [(String, String)],
58	}
59	
60	impl<'a> Request<'a> {
61	    pub fn get(path: &'a str) -> Request<'a> {
62	        Request { method: HttpMethod::Get, path, form: &[] }
63	    }
64	    pub fn post(path: &'a str, form: &'a [(String, String)]) -> Request<'a> {
65	        Request { method: HttpMethod::Post, path, form }
66	    }
67	    fn field(&self, key: &str) -> &str {
68	        self.form
69	            .iter()
70	            .find(|(k, _)| k == key)
71	            .map(|(_, v)| v.as_str())
72	            .unwrap_or("")
73	    }
74	}
