76	/// An outgoing response. `location` is set only for `303` redirects.
77	#[derive(Debug, PartialEq, Eq, Clone)]
78	pub struct Response {
79	    pub status: u16,
80	    pub content_type: &'static str,
81	    pub body: String,
82	    pub location: Option<String>,
83	}
84	
85	impl Response {
86	    fn json(body: String) -> Response {
87	        Response { status: 200, content_type: CT_JSON, body, location: None }
88	    }
89	    fn html(body: String) -> Response {
90	        Response { status: 200, content_type: CT_HTML, body, location: None }
91	    }
92	    fn text(body: String) -> Response {
93	        Response { status: 200, content_type: CT_TEXT, body, location: None }
94	    }
95	    fn see_other(location: String) -> Response {
96	        Response { status: 303, content_type: CT_TEXT, body: String::new(), location: Some(location) }
97	    }
98	    fn not_found(echoed_path: &str) -> Response {
99	        Response { status: 404, content_type: CT_HTML, body: errors::render_not_found(echoed_path), location: None }
100	    }
101	}
