117	/// A request for a `main/*` content pane, resolved to the prover.
118	pub enum MainReq<'a> {
119	    Help,
120	    Message,
121	    Rules,
122	    Tactic,
123	    Cases { refined: bool, level: usize, n: usize },
124	    Lemma(&'a str),
125	    Proof { lemma: &'a str, path: &'a [String] },
126	}
