128	/// The prover-supplied callbacks. The web layer treats every returned string as an
129	/// opaque fragment; the *decisions* around these calls (version allocation, route
130	/// dispatch, envelope shape) live in [`Server::dispatch`].
131	pub trait ProverOps {
132	    /// Opaque per-version theory handle held by the [`Server`].
133	    type Theory;
134	
135	    // ---- pretty-printers / fragment producers ----
136	    /// Shell metadata (theory name, Tamarin version string, source filename).
137	    fn meta(&self, thy: &Self::Theory) -> Meta;
138	    /// The `source`/`message` body: the pretty-printed theory source, verbatim.
139	    fn source_text(&self, thy: &Self::Theory) -> String;
140	    /// Inner HTML of the west proof-script pane at `index`.
141	    fn west_pane(&self, thy: &Self::Theory, index: u64) -> String;
142	    /// Center-pane content (html + title) for a `main/*` view at `index`.
143	    fn main_content(&self, thy: &Self::Theory, index: u64, req: &MainReq) -> Content;
144	    /// Raw (unescaped) current source of a lemma, for the edit form.
145	    fn lemma_source(&self, thy: &Self::Theory, name: &str) -> Option<String>;
146	    /// Graphviz DOT for an `interactive-graph-def` node.
147	    fn graph_dot(&self, thy: &Self::Theory, tail: &[String]) -> String;
148	    /// The `next`/`prev` target URL (bare path), computed by the prover's proof-tree
149	    /// traversal for `mode`/`lemma` at `index`.
150	    fn nav_target(&self, thy: &Self::Theory, index: u64, dir: NavDir, mode: &str, lemma: &str) -> String;
151	
152	    // ---- mutations ----
153	    /// Apply proof method `n` at `(lemma, path)`. Returns the new theory and the
154	    /// resulting focus path (the prover's next open goal, incl. the root `_`).
155	    fn apply_method(&self, thy: &Self::Theory, lemma: &str, n: usize, path: &[String]) -> (Self::Theory, Vec<String>);
156	    /// Autoprove per `spec`. Returns the new theory and resulting focus path.
157	    fn autoprove(&self, thy: &Self::Theory, spec: &Autoprove) -> (Self::Theory, Vec<String>);
158	    /// Edit lemma `name` in place. `Some` = the modified theory; `None` = parse/wf
159	    /// failure (the web layer then re-renders the form with the theory unchanged).
160	    fn edit_lemma(&self, thy: &Self::Theory, name: &str, text: &str) -> Option<Self::Theory>;
161	    /// Add a lemma at position `pos`. `Some`/`None` as for [`Self::edit_lemma`].
162	    fn add_lemma(&self, thy: &Self::Theory, pos: &str, text: &str) -> Option<Self::Theory>;
163	    /// Delete lemma `name` in place, returning the modified theory.
164	    fn delete_lemma(&self, thy: &Self::Theory, name: &str) -> Self::Theory;
165	}
166	
167	/// The interactive server's per-theory state: the version map plus the monotonic
168	/// next-index counter. Generic over the prover callbacks.
169	pub struct Server<T: ProverOps> {
170	    ops: T,
171	    /// index -> theory version. Version 1 is the originally loaded theory.
172	    versions: BTreeMap<u64, T::Theory>,
173	    /// Next free version index (monotonic; `= max ever allocated + 1`).
174	    next_index: u64,
175	}
176	
177	impl<T: ProverOps> Server<T> {
178	    /// Create a server holding `base` as version 1.
179	    pub fn new(ops: T, base: T::Theory) -> Server<T> {
180	        let mut versions = BTreeMap::new();
181	        versions.insert(1, base);
182	        Server { ops, versions, next_index: 2 }
183	    }
184	
185	    /// Version indices currently allocated (ascending). All are resolvable.
186	    pub fn versions(&self) -> Vec<u64> {
187	        self.versions.keys().copied().collect()
188	    }
189	
190	    fn resolve(&self, index: &Index) -> Option<u64> {
191	        // Real requests always carry a numeric index; `#` is a crawl placeholder
192	        // that never reaches a live server (a literal `#` is a URL fragment, and
193	        // `%23` 404s — live [L2]), so it resolves to nothing here.
194	        match index {
195	            Index::Num(v) if self.versions.contains_key(v) => Some(*v),
196	            _ => None,
197	        }
198	    }
199	
200	    /// Dispatch a request to a response, mutating version state as observed.
201	    pub fn dispatch(&mut self, req: &Request) -> Response {
202	        let route = match Route::parse(req.path) {
203	            Some(r) => r,
204	            None => return Response::not_found(req.path),
205	        };
206	        let index = match self.resolve(&route.index) {
207	            Some(v) => v,
208	            None => return Response::not_found(req.path),
209	        };
210	        match (req.method, &route.handler) {
211	            // `main/method` is delivered under `main` but is a proof operation
212	            // (allocates a new version); intercept it before the read-only views.
213	            (HttpMethod::Get, Handler::Main(Main::Method { lemma, n, path })) => {
214	                self.get_method(index, &lemma.clone(), *n, &path.clone())
215	            }
216	            (HttpMethod::Get, Handler::Main(m)) => self.get_main(index, m),
217	            (HttpMethod::Get, Handler::Overview(tail)) => self.get_overview(index, &OverviewView::parse(tail)),
218	            (HttpMethod::Get, Handler::Autoprove(tail)) => match Autoprove::parse(tail) {
219	                Some(ap) => self.proof_op_autoprove(index, &ap),
220	                None => Response::not_found(req.path),
221	            },
222	            (HttpMethod::Get, Handler::Next(tail)) => self.get_nav(index, NavDir::Next, tail, req.path),
223	            (HttpMethod::Get, Handler::Prev(tail)) => self.get_nav(index, NavDir::Prev, tail, req.path),
224	            (HttpMethod::Get, Handler::Source) | (HttpMethod::Get, Handler::Message) => {
225	                Response::text(self.ops.source_text(&self.versions[&index]))
226	            }
227	            (HttpMethod::Get, Handler::Intdot(tail)) => self.get_intdot(index, tail),
228	            (HttpMethod::Get, Handler::InteractiveGraphDef(tail)) => {
229	                Response::text(self.ops.graph_dot(&self.versions[&index], tail))
230	            }
231	            // Structural-edit POST form targets: /thy/trace/V/edit/{verb}/{name}
232	            (HttpMethod::Post, Handler::Other { name, tail }) if name == "edit" => {
233	                self.post_edit(index, tail, req)
234	            }
235	            _ => Response::not_found(req.path),
236	        }
237	    }
238	
239	    // ---- GET main/* : JSON envelopes ----
240	    fn get_main(&self, index: u64, m: &Main) -> Response {
241	        let thy = &self.versions[&index];
242	        let content = match m {
243	            Main::Help => self.ops.main_content(thy, index, &MainReq::Help),
244	            Main::Message => self.ops.main_content(thy, index, &MainReq::Message),
245	            Main::Rules => self.ops.main_content(thy, index, &MainReq::Rules),
246	            Main::Tactic => self.ops.main_content(thy, index, &MainReq::Tactic),
247	            Main::Cases { refined, level, n } => {
248	                self.ops.main_content(thy, index, &MainReq::Cases { refined: *refined, level: *level, n: *n })
249	            }
250	            Main::Lemma(name) => self.ops.main_content(thy, index, &MainReq::Lemma(name)),
251	            Main::Proof { lemma, path } => {
252	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path })
253	            }
254	            // Forms are web-layer templates; only the edit form needs prover input.
255	            Main::Edit(name) => {
256	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
257	                Content { html: forms::edit_form(name, &src), title: format!("Edit Lemma: {name}") }
258	            }
259	            Main::Add(pos) => Content { html: forms::add_form(pos), title: "Add new Lemma".to_string() },
260	            Main::Delete(name) => Content { html: forms::delete_form(name), title: format!("Delete {name}") },
261	            // `Method` is a proof op intercepted in `dispatch`; unreachable here.
262	            Main::Method { .. } => return Response::not_found("method"),
263	            Main::Other(_) => return Response::not_found("main"),
264	        };
265	        Response::json(envelope::render_content(&content.html, &content.title))
266	    }
267	
268	    // ---- GET overview/* : full-page HTML ----
269	    fn get_overview(&self, index: u64, view: &OverviewView) -> Response {
270	        let thy = &self.versions[&index];
271	        let meta = self.ops.meta(thy);
272	        let west = self.ops.west_pane(thy, index);
273	        let center = self.center_for(thy, index, view);
274	        let params = page::PageParams {
275	            theory_name: &meta.name,
276	            index,
277	            version: &meta.version,
278	            filename: &meta.filename,
279	        };
280	        Response::html(page::render_page(&params, &west, &center))
281	    }
282	
283	    /// The center-pane inner HTML for an overview view. Observed (BEHAVIOR §12):
284	    /// the center pane is the corresponding `main/*` html **plus one trailing
285	    /// space**.
286	    fn center_for(&self, thy: &T::Theory, index: u64, view: &OverviewView) -> String {
287	        let inner = match view {
288	            OverviewView::Help => self.ops.main_content(thy, index, &MainReq::Help).html,
289	            OverviewView::Proof { lemma, path } => {
290	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path }).html
291	            }
292	            OverviewView::Edit(name) => {
293	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
294	                forms::edit_form(name, &src)
295	            }
296	            OverviewView::Add(pos) => forms::add_form(pos),
297	            OverviewView::Other(_) => String::new(),
298	        };
299	        format!("{inner} ")
300	    }
301	
302	    // ---- GET next/prev : text/plain bare URL ----
303	    fn get_nav(&self, index: u64, dir: NavDir, tail: &[String], path: &str) -> Response {
304	        match Nav::parse(dir, tail) {
305	            Some(nav) => Response::text(self.ops.nav_target(&self.versions[&index], index, dir, &nav.mode, &nav.lemma)),
306	            None => Response::not_found(path),
307	        }
308	    }
309	
310	    // ---- GET intdot : html mini page (handler swapped intdot -> i-g-def, same tail) ----
311	    fn get_intdot(&self, index: u64, tail: &[String]) -> Response {
312	        let meta = self.ops.meta(&self.versions[&index]);
313	        let trailing = tail.join("/");
314	        Response::html(intdot::render_intdot(&meta.name, &intdot::dotsrc_path(index, &trailing)))
315	    }
316	
317	    // ---- proof operations: allocate a NEW version, answer JSON {redirect} ----
318	    fn get_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
319	        let (new_thy, focus) = self.ops.apply_method(&self.versions[&index], lemma, n, path);
320	        let new_index = self.commit_new_version(new_thy);
321	        Response::json(envelope::render_redirect(&overview_proof_path(new_index, lemma, &focus)))
322	    }
323	
324	    fn proof_op_autoprove(&mut self, index: u64, ap: &Autoprove) -> Response {
325	        let (new_thy, focus) = self.ops.autoprove(&self.versions[&index], ap);
326	        let new_index = self.commit_new_version(new_thy);
327	        Response::json(envelope::render_redirect(&overview_proof_path(new_index, &ap.lemma, &focus)))
328	    }
329	
330	    fn commit_new_version(&mut self, thy: T::Theory) -> u64 {
331	        let new_index = self.next_index;
332	        self.next_index += 1;
333	        self.versions.insert(new_index, thy);
334	        new_index
335	    }
336	
337	    // ---- structural POST: mutate IN PLACE, answer 303 (or 200 form on failure) ----
338	    fn post_edit(&mut self, index: u64, tail: &[String], req: &Request) -> Response {
339	        let (verb, name) = match tail {
340	            [v, n] => match EditVerb::parse(v) {
341	                Some(verb) => (verb, n.clone()),
342	                None => return Response::not_found(req.path),
343	            },
344	            _ => return Response::not_found(req.path),
345	        };
346	        match verb {
347	            EditVerb::Delete => {
348	                let new_thy = self.ops.delete_lemma(&self.versions[&index], &name);
349	                self.versions.insert(index, new_thy);
350	                Response::see_other(format!("/thy/trace/{index}/overview/help"))
351	            }
352	            EditVerb::Edit => {
353	                let text = req.field("lemma-text");
354	                match self.ops.edit_lemma(&self.versions[&index], &name, text) {
355	                    Some(new_thy) => {
356	                        self.versions.insert(index, new_thy);
357	                        Response::see_other(format!("/thy/trace/{index}/overview/edit/{name}"))
358	                    }
359	                    // Failure: theory unchanged, re-render the full-page edit form.
360	                    None => self.get_overview(index, &OverviewView::Edit(name)),
361	                }
362	            }
363	            EditVerb::Add => {
364	                let text = req.field("lemma-text");
365	                match self.ops.add_lemma(&self.versions[&index], &name, text) {
366	                    Some(new_thy) => {
367	                        self.versions.insert(index, new_thy);
368	                        Response::see_other(format!("/thy/trace/{index}/overview/add/{name}"))
369	                    }
370	                    None => self.get_overview(index, &OverviewView::Add(name)),
371	                }
372	            }
373	        }
374	    }
375	
376	    /// Apply a proof method that arrived as a parsed `Main::Method` (proof op).
377	    /// Exposed so a caller that pre-parses `main/method` can drive the version
378	    /// bump directly; the normal path routes GET `main/method` through here.
379	    pub fn apply_main_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
380	        self.get_method(index, lemma, n, path)
381	    }
382	}
383	
384	/// Build an `overview/proof/{lemma}[/focus…]` URL for version `index`.
385	fn overview_proof_path(index: u64, lemma: &str, focus: &[String]) -> String {
386	    let mut s = format!("/thy/trace/{index}/overview/proof/{lemma}");
387	    for seg in focus {
388	        s.push('/');
389	        s.push_str(seg);
390	    }
391	    s
392	}
