1	//! `web-clean` — a clean-room reimplementation of the response bodies produced
2	//! by the tamarin-prover interactive web UI.
3	//!
4	//! This crate reproduces the *web layer's* output: the URL route grammar, the
5	//! JSON response envelopes, and the HTML/DOT/text page templates. Content that
6	//! the prover produces (pretty-printed terms, constraint systems, proof-method
7	//! names, graph bodies) is treated as opaque input supplied by the caller — the
8	//! crate reproduces the scaffolding, escaping, links and envelopes around it.
9	//!
10	//! Everything here was derived from black-box observation of captured responses
11	//! and live probing; see `workspace/BEHAVIOR.md` for the observed spec.
12	//!
13	//! Module map:
14	//! * [`route`] — parse a request path into a structured route (the grammar).
15	//! * [`dispatch`] — the UI state machine: route dispatch, theory-version
16	//!   management, and response-envelope assembly, over a `ProverOps` trait.
17	//! * [`envelope`] — the two JSON response shapes (`{html,title}`, `{redirect}`).
18	//! * [`escape`] — HTML entity escaping.
19	//! * [`page`] — the full theory-view HTML shell (the `overview/*` pages).
20	//! * [`proofscript`] — the proof-script (west) pane and proof-tree line grammar.
21	//! * [`forms`] — the edit / delete / add-lemma form bodies.
22	//! * [`intdot`] — the `intdot` mini-page and empty-graph DOT skeleton.
23	//! * [`text`] — the plain-text bodies (`source`/`message`, `next`/`prev`).
24	//! * [`errors`] — the 404 Not Found page.
25	
26	pub mod dispatch;
27	pub mod envelope;
28	pub mod errors;
29	pub mod escape;
30	pub mod forms;
31	pub mod intdot;
32	pub mod page;
33	pub mod proofscript;
34	pub mod route;
35	pub mod text;
36	
37	mod notfound_template;
38	mod shell_template;
39

1	//! Error response pages.
2	//!
3	//! Observed by live probing: a request that does not match any route (unknown
4	//! handler, non-existent theory index, or a path segment the router rejects
5	//! such as a URL-encoded `%23`) returns HTTP 404 with a full HTML page. The
6	//! page reuses the standard `<head>` link set and the standard page tail; its
7	//! body is just the loading bar, an `<h1>Not Found</h1>`, and the echoed
8	//! request path in a `<p>`. The echoed path is HTML-escaped.
9	
10	use crate::escape::html_escape;
11	use crate::notfound_template::NOT_FOUND;
12	
13	/// Render the 404 Not Found page for a given (already percent-encoded) request
14	/// path. The path is HTML-escaped before being echoed into the body.
15	pub fn render_not_found(request_path: &str) -> String {
16	    NOT_FOUND.replace("§PATH§", &html_escape(request_path))
17	}
18	
19	#[cfg(test)]
20	mod tests {
21	    use super::*;
22	
23	    #[test]
24	    fn not_found_echoes_path() {
25	        let p = render_not_found("/thy/trace/1/main/nope");
26	        assert!(p.contains("<title>Not Found</title>"));
27	        assert!(p.contains("<h1>Not Found</h1>\n<p>/thy/trace/1/main/nope</p>"));
28	        assert!(p.ends_with("</body></html>"));
29	    }
30	}
