1	//! Plain-text (`text/plain`) response bodies.
2	//!
3	//! Observed `kind=text` routes:
4	//! * `source` and `message` — identical: the pretty-printed theory source (the
5	//!   prover's output verbatim; no trailing newline in the response body). The
6	//!   web layer is a pass-through, so [`source_body`] is the identity.
7	//! * `next/<mode>/proof/<lemma>` and `prev/<mode>/proof/<lemma>` — a single URL
8	//!   path string naming where the client should navigate (resolved numeric
9	//!   index), e.g. `/thy/trace/1/main/proof/unforgeability`. Also a pass-through
10	//!   of a value the prover computes; [`nav_target`] is the identity.
11	
12	/// The `source` / `message` text body: the theory source, returned verbatim.
13	pub fn source_body(theory_source: &str) -> &str {
14	    theory_source
15	}
16	
17	/// The `next` / `prev` navigation body: a target URL path, returned verbatim.
18	pub fn nav_target(path: &str) -> &str {
19	    path
20	}
21	
22	/// Build a `main/proof` navigation target path.
23	pub fn main_proof_path(index: u64, lemma: &str, proof_path: &[&str]) -> String {
24	    let mut s = format!("/thy/trace/{index}/main/proof/{lemma}");
25	    for seg in proof_path {
26	        s.push('/');
27	        s.push_str(seg);
28	    }
29	    s
30	}
31	
32	#[cfg(test)]
33	mod tests {
34	    use super::*;
35	
36	    #[test]
37	    fn nav_path_builder() {
38	        assert_eq!(
39	            main_proof_path(1, "unforgeability", &[]),
40	            "/thy/trace/1/main/proof/unforgeability"
41	        );
42	        assert_eq!(
43	            main_proof_path(3, "exec", &["_", "B_2"]),
44	            "/thy/trace/3/main/proof/exec/_/B_2"
45	        );
46	    }
47	}
